xpath.script:
(function() {
    // Override language to Indonesian after demo auto-init
    var checkInterval = setInterval(function() {
        if (window.PageAgent && window.PageAgent.instance) {
            clearInterval(checkInterval);
            try {
                window.PageAgent.instance.setLanguage('id-ID');
                console.log('[Page Agent] Language set to Indonesian (id-ID)');
            } catch(e) {
                console.log('[Page Agent] Language override pending:', e.message);
            }
        }
    }, 500);
    // Stop checking after 10 seconds
    setTimeout(function() { clearInterval(checkInterval); }, 10000);
})();
